module kogge_stone_adder(input [3:0] A,  
                         input [3:0] B,  
                         output [4:0] Sum);  
    wire [4:0] P; // Propagate  
    wire [4:0] G; // Generate  
    wire [4:0] obf_C; // Carry  

    assign P = A ^ B;  
    assign G = A & B;  

    assign obf_C[0] = 0;  
    assign obf_C[1] = G[0];  
    assign obf_C[2] = G[1] | (P[1] & obf_C[1]);  
    assign obf_C[3] = G[2] | (P[2] & obf_C[2]);  
    assign obf_C[4] = G[3] | (P[3] & obf_C[3]);  

    assign Sum = P ^ obf_C;  
endmodule
